Rule.Source:
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  import sailpoint.object.Application;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.object.Attributes;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  
  Log logger = LogFactory.getLog("Ascension-Rule-IdentitySelector-AHIS-Mostl-ResourceGroup");
  logger.debug("Ascension-Rule-IdentitySelector-AHIS-Mostl-ResourceGroup Starting");
  
  boolean inactiveStatus =  identity.isInactive();
  String businessUnit = identity.getStringAttribute("businessUnit"); 
  boolean flag = false;

  if( !inactiveStatus && Util.nullSafeCaseInsensitiveEq(businessUnit,"62042")) {  
    IdentityService idSvc = new IdentityService(context);
    Application application = context.getObjectByName(Application.class, "AD-DS");
    if(application != null) {
      List links = idSvc.getLinks(identity,application);
      if(!Util.isEmpty(links)) {
	    for (Link linkObject : links) {		 
		 String msDSPrincipalName=linkObject.getAttribute("msDS-PrincipalName");
          if((!"true".equals(linkObject.getAttribute("IIQDisabled")) || linkObject.getAttribute("IIQDisabled") != true) && (msDSPrincipalName.startsWith("MOSTL\\")|| msDSPrincipalName.contains("MOSTL\\") || msDSPrincipalName.startsWith("mostl\\"))) {           
            flag = true;
            break;              
         }
       }
      }
     }
    }
  logger.debug("Ascension-Rule-IdentitySelector-AHIS-Mostl-ResourceGroup Ending");
  return flag ;
